              "timeout": 5
            },
            {
              "type": "prompt",
              "prompt": "Deep analysis of bash command: $TOOL_INPUT",
              "timeout": 15
            }
          ]
        }
      ]
    }

The command hook does fast deterministic checks, while the prompt hook handles complex reasoning.

